def infinite_cycles(self):
    # Chain assignment for initial dictionary setup
    terminates = {t: True for t in self.Terminals}
    terminates['$end'] = True

    # Nonterminals, initialize to False with chain assignment
    terminates.update({n: False for n in self.Nonterminals})

    # Propagate termination until no change occurs
    while True:
        some_change = False
        for (n, pl) in self.Prodnames.items():
            for p in pl:
                # Production p terminates if all symbols on the rhs terminate
                p_terminates = True
                for s in p.prod:
                    if not terminates[s]:
                        p_terminates = False
                        break

                if p_terminates:
                    if not terminates[n]:
                        terminates[n] = some_change = True
                    break

        if not some_change:
            break

    infinite = []
    for (s, term) in terminates.items():
        if not term and (s in self.Prodnames or s in self.Terminals or s == 'error'):
            infinite.append(s)

    return infinite

